import { useEffect, useState } from 'react';
import api from '../../api/client';
import AppNavbar from '../../components/AppNavbar';
import TicketList from '../../components/TicketList';

export default function AdminDashboard() {
  const [summary, setSummary] = useState({
    total: 0,
    open: 0,
    in_progress: 0,
    resolved_by_support: 0,
    sent_to_developer: 0,
    developer_in_progress: 0,
    closed: 0,
    reopened: 0,
  });

  const [departments, setDepartments] = useState([]);
  const [modules, setModules] = useState([]);
  const [submodules, setSubmodules] = useState([]);
  const [reportedToList, setReportedToList] = useState([]);
  const [emailConfigs, setEmailConfigs] = useState([]);
  const [refreshKey, setRefreshKey] = useState(0);

  const loadData = async () => {
    try {
      const [
        summaryRes,
        deptRes,
        moduleRes,
        submoduleRes,
        reportedRes,
        emailRes,
      ] = await Promise.all([
        api.get('/dashboard/summary/'),
        api.get('/masters/departments/'),
        api.get('/masters/modules/'),
        api.get('/masters/submodules/'),
        api.get('/masters/reported-to/'),
        api.get('/masters/email-configs/'),
      ]);

      setSummary(summaryRes.data);
      setDepartments(deptRes.data);
      setModules(moduleRes.data);
      setSubmodules(submoduleRes.data);
      setReportedToList(reportedRes.data);
      setEmailConfigs(emailRes.data);
    } catch (err) {
      console.error('Failed to load admin dashboard data', err);
    }
  };

  useEffect(() => {
    loadData();
  }, [refreshKey]);

  return (
    <>
      <AppNavbar />
      <div className="container mt-4">
        <h2 className="mb-4">Admin Dashboard</h2>

        <div className="row g-3 mb-4">
          <div className="col-md-3"><div className="card"><div className="card-body"><h6>Total</h6><h2>{summary.total || 0}</h2></div></div></div>
          <div className="col-md-3"><div className="card"><div className="card-body"><h6>Open</h6><h2>{summary.open || 0}</h2></div></div></div>
          <div className="col-md-3"><div className="card"><div className="card-body"><h6>In Progress</h6><h2>{summary.in_progress || 0}</h2></div></div></div>
          <div className="col-md-3"><div className="card"><div className="card-body"><h6>Resolved by Support</h6><h2>{summary.resolved_by_support || 0}</h2></div></div></div>
          <div className="col-md-3"><div className="card"><div className="card-body"><h6>Sent to Developer</h6><h2>{summary.sent_to_developer || 0}</h2></div></div></div>
          <div className="col-md-3"><div className="card"><div className="card-body"><h6>Developer In Progress</h6><h2>{summary.developer_in_progress || 0}</h2></div></div></div>
          <div className="col-md-3"><div className="card"><div className="card-body"><h6>Closed</h6><h2>{summary.closed || 0}</h2></div></div></div>
          <div className="col-md-3"><div className="card"><div className="card-body"><h6>Reopened</h6><h2>{summary.reopened || 0}</h2></div></div></div>
        </div>

        <div className="row g-4 mb-4">
          <div className="col-md-6">
            <div className="card h-100">
              <div className="card-body">
                <h5 className="mb-3">Departments</h5>
                <ul className="list-group">
                  {departments.length ? departments.map((d) => (
                    <li key={d.id} className="list-group-item">{d.department_name}</li>
                  )) : <li className="list-group-item">No departments found</li>}
                </ul>
              </div>
            </div>
          </div>

          <div className="col-md-6">
            <div className="card h-100">
              <div className="card-body">
                <h5 className="mb-3">Modules</h5>
                <ul className="list-group">
                  {modules.length ? modules.map((m) => (
                    <li key={m.id} className="list-group-item">{m.module_name}</li>
                  )) : <li className="list-group-item">No modules found</li>}
                </ul>
              </div>
            </div>
          </div>

          <div className="col-md-6">
            <div className="card h-100">
              <div className="card-body">
                <h5 className="mb-3">Submodules</h5>
                <ul className="list-group">
                  {submodules.length ? submodules.map((s) => (
                    <li key={s.id} className="list-group-item">
                      {s.submodule_name}
                    </li>
                  )) : <li className="list-group-item">No submodules found</li>}
                </ul>
              </div>
            </div>
          </div>

          <div className="col-md-6">
            <div className="card h-100">
              <div className="card-body">
                <h5 className="mb-3">Reported To</h5>
                <ul className="list-group">
                  {reportedToList.length ? reportedToList.map((r) => (
                    <li key={r.id} className="list-group-item">{r.person_name}</li>
                  )) : <li className="list-group-item">No names found</li>}
                </ul>
              </div>
            </div>
          </div>

          <div className="col-md-12">
            <div className="card">
              <div className="card-body">
                <h5 className="mb-3">Email Configurations</h5>
                <div className="table-responsive">
                  <table className="table table-bordered">
                    <thead>
                      <tr>
                        <th>Name</th>
                        <th>From</th>
                        <th>To</th>
                        <th>CC</th>
                      </tr>
                    </thead>
                    <tbody>
                      {emailConfigs.length ? emailConfigs.map((e) => (
                        <tr key={e.id}>
                          <td>{e.config_name}</td>
                          <td>{e.from_email}</td>
                          <td>{e.to_email}</td>
                          <td>{e.cc_emails}</td>
                        </tr>
                      )) : (
                        <tr>
                          <td colSpan="4">No email configurations found</td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-body">
            <h4 className="mb-3">All Tickets</h4>
            <TicketList refreshKey={refreshKey} />
          </div>
        </div>
      </div>
    </>
  );
}
